SELECT
s.id
FROM t_ctr_contract_settlement s where s.settle_status = '2' and  s.business_type = 'ZY-BB'
and s.settle_total_flg = false
and s.match_credit_flg =  #{matchCreditFlg}

	and s.sell_match_user_id = #{matchUserId}


	and extract(year_month from s.summary_date) = #{settlementDate}
